def find_in_hadith(term):
    normt = normalize_arabic(term)
    results = []
    for rec in hadiths:
        for field in ['hadithTxt','Matn']:
            tx = rec.get(field) or ""
            if not tx:
                continue
            if normt in normalize_arabic(tx):
                results.append((rec['BookID'], rec['title'], tx, rec['Matn']))
                break
    return results

