def search_hadith_tokens(tokens):
    tok_norm = [normalize_arabic(t) for t in tokens]
    results = []
    for rec in hadiths:
        for field in ['Matn','hadithTxt']:
            tx = rec.get(field) or ""
            if not tx: 
                continue
            sn = normalize_arabic(tx)
            if all(t in sn for t in tok_norm):
                results.append((rec['BookID'], rec['title'], tx, rec['Matn']))
                break
    return results

